import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
// import './Login.css';

const api = axios.create({ 
  baseURL: 'http://localhost:5000',
  withCredentials: true 
});

function Login() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [debugInfo, setDebugInfo] = useState({});
  const [cookies, setCookies] = useState('');
  const [showDebug, setShowDebug] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    updateCookies();
  }, []);

  const updateCookies = () => {
    const cookiesString = document.cookie || 'Нет cookies';
    setCookies(cookiesString);

    const allCookies = {};
    document.cookie.split(';').forEach(cookie => {
      const [key, value] = cookie.trim().split('=');
      if (key) allCookies[key] = value;
    });
    setDebugInfo(prev => ({...prev, allCookies}));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await api.post('/login', {
        login: form.login,
        password: form.password
      });

      setDebugInfo(prev => ({
        ...prev,
        loginResponse: response.data,
        loginStatus: response.status,
        loginHeaders: response.headers
      }));

      if (response.status === 200) {
        updateCookies();
        navigate('/sings');
      }
    } catch (err) {
      let errorMessage = '';

      if (err.response) {
        errorMessage = err.response.data.message || 'Ошибка входа';
        setDebugInfo(prev => ({
          ...prev,
          errorResponse: err.response.data,
          errorStatus: err.response.status
        }));
      } else if (err.request) {
        errorMessage = 'Нет ответа от сервера. Проверьте, запущен ли Flask.';
      } else {
        errorMessage = 'Ошибка при отправке запроса';
      }

      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: value
    }));
    if (error) setError('');
  };

  const testProtectedEndpoint = async () => {
    try {
      const response = await api.get('/table');

      setDebugInfo(prev => ({
        ...prev,
        testResponse: response.data,
        testStatus: response.status,
        testHeaders: response.headers,
        testTimestamp: new Date().toISOString()
      }));
    } catch (err) {
      setDebugInfo(prev => ({
        ...prev,
        testError: err.response?.data || err.message,
        testErrorStatus: err.response?.status
      }));
    }
  };

  const handleQuickLogin = async (login, password) => {
    setForm({ login, password });

    // Ждем немного для обновления состояния формы
    setTimeout(async () => {
      await handleSubmit({ preventDefault: () => {} });
    }, 100);
  };

  return (
    <div className="app-container">
      <div className="app-card">
        <h2 className="app-title">Вход в систему</h2>
        <p className="app-subtitle">Введите логин и пароль</p>

        {error && (
          <div className="error-message">
            <strong>Ошибка:</strong> {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="app-form">
          <div className="form-group">
            <label htmlFor="login">Логин:</label>
            <input
              type="text"
              name="login"
              value={form.login}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Введите логин"
              required
              disabled={loading}
              autoComplete="username"
              autoFocus
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Пароль:</label>
            <input
              type="password"
              name="password"
              value={form.password}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Введите пароль"
              required
              disabled={loading}
              autoComplete="current-password"
            />
          </div>

          <button
            type="submit"
            className="login-button"
            disabled={loading || !form.login || !form.password}
          >
            {loading ? 'Вход...' : 'Войти'}
          </button>
        </form>

        <div className="demo-credentials">
          <h4>Тестовые учетные данные:</h4>
          <button 
            onClick={() => handleQuickLogin('admin', 'admin')}
            className="demo-button"
            disabled={loading}
          >
            Войти как admin/admin
          </button>
        </div>
      </div>

      <div className="debug-panel">
        <div className="debug-header">
          <h3>Отладочная информация</h3>
          <button 
            onClick={() => setShowDebug(!showDebug)}
            className="toggle-debug-btn"
          >
            {showDebug ? 'Скрыть' : 'Показать'}
          </button>
        </div>

        {showDebug && (
          <>
            <div className="debug-section">
              <h4>Cookies:</h4>
              <pre className="cookies-display">{cookies}</pre>
              <button onClick={updateCookies} className="refresh-button">
                Обновить cookies
              </button>
            </div>

            <div className="debug-section">
              <h4>Тест защищенного эндпоинта:</h4>
              <button 
                onClick={testProtectedEndpoint} 
                className="test-button"
              >
                Тест /table
              </button>
            </div>

            <div className="debug-section">
              <h4>Информация отладки:</h4>
              <pre className="debug-info">
                {JSON.stringify(debugInfo, null, 2)}
              </pre>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default Login;
